fn create_inline_element_from_span(span: &ParsedSpan, is_code_block: bool) -> InlineElement {
    InlineElement {
        content: InlineContent::Text(span.text.clone()),
        fmt_font_bold: if span.bold { Some(true) } else { None },
        fmt_font_italic: if span.italic { Some(true) } else { None },
        fmt_font_underline: if span.underline { Some(true) } else { None },
        fmt_font_strikeout: if span.strikeout { Some(true) } else { None },
        fmt_font_family: if span.code || is_code_block {
            Some("monospace".to_string())
        } else {
            None
        },
        fmt_anchor_href: span.link_href.clone(),
        fmt_is_anchor: if span.link_href.is_some() {
            Some(true)
        } else {
            None
        },
        ..InlineElement::default()
    }
}

fn import_parsed_blocks(
    uow: &mut Box<dyn ImportMarkdownUnitOfWorkTrait>,
    parsed_blocks: &[ParsedBlock],
    progress_callback: &dyn Fn(common::long_operation::OperationProgress),
    cancel_flag: &Arc<std::sync::atomic::AtomicBool>,
) -> Result<i64> {
    use std::sync::atomic::Ordering;

    progress_callback(common::long_operation::OperationProgress::new(
        10.0,
        Some("Parsed content, building document...".to_string()),
    ));

    // Step 1: Get Root and Document
    let root = uow
        .get_root(&ROOT_ENTITY_ID)?
        .ok_or_else(|| anyhow!("Root entity not found"))?;

    let doc_ids = uow.get_root_relationship(
        &root.id,
        &common::direct_access::root::RootRelationshipField::Document,
    )?;
    let doc_id = *doc_ids
        .first()
        .ok_or_else(|| anyhow!("Root has no associated Document"))?;

    // Step 2: Remove existing frames
    let frame_ids = uow.get_document_relationship(
        &doc_id,
        &common::direct_access::document::DocumentRelationshipField::Frames,
    )?;
    for frame_id in &frame_ids {
        uow.remove_frame(frame_id)?;
    }

    if cancel_flag.load(Ordering::Relaxed) {
        return Err(anyhow!("Operation was cancelled"));
    }

    progress_callback(common::long_operation::OperationProgress::new(
        20.0,
        Some("Creating new document structure...".to_string()),
    ));

    // Step 3: Create root frame
    let new_frame = Frame::default();
    let created_frame = uow.create_frame(&new_frame, doc_id, -1)?;

    // Step 4: Create blocks with inline elements
    let total_blocks = parsed_blocks.len();
    let mut total_chars: i64 = 0;
    let mut document_position: i64 = 0;
    let mut block_ids: Vec<i64> = Vec::new();

    for (i, parsed_block) in parsed_blocks.iter().enumerate() {
        if cancel_flag.load(Ordering::Relaxed) {
            return Err(anyhow!("Operation was cancelled"));
        }

        // Build plain text from spans
        let plain_text: String = parsed_block.spans.iter().map(|s| s.text.as_str()).collect();
        let line_len = plain_text.chars().count() as i64;

        // Create Block
        let block = Block {
            plain_text,
            text_length: line_len,
            document_position,
            fmt_heading_level: parsed_block.heading_level,
            ..Block::default()
        };

        let created_block = uow.create_block(&block, created_frame.id, -1)?;

        // Create inline elements from spans
        for span in &parsed_block.spans {
            let element = create_inline_element_from_span(span, parsed_block.is_code_block);
            uow.create_inline_element(&element, created_block.id, -1)?;
        }

        // Handle list items
        if let Some(ref list_style) = parsed_block.list_style {
            let list = List {
                style: list_style.clone(),
                ..List::default()
            };
            let created_list = uow.create_list(&list, doc_id, -1)?;

            uow.set_block_relationship(
                &created_block.id,
                &common::direct_access::block::BlockRelationshipField::List,
                &[created_list.id],
            )?;
        }

        block_ids.push(created_block.id as i64);
        total_chars += line_len;

        document_position += line_len;
        if i < total_blocks - 1 {
            document_position += 1;
        }

        // Report progress
        if i % 10 == 0 {
            let pct = 20.0 + (i as f32 / total_blocks as f32) * 70.0;
            progress_callback(common::long_operation::OperationProgress::new(
                pct,
                Some(format!("Processing block {}/{}", i + 1, total_blocks)),
            ));
        }
    }

    // Step 5: Update frame child_order
    let mut updated_frame = uow
        .get_frame(&created_frame.id)?
        .ok_or_else(|| anyhow!("Created frame not found"))?;
    updated_frame.child_order = block_ids;
    uow.update_frame(&updated_frame)?;

    // Step 6: Update document stats
    let mut updated_doc = uow
        .get_document(&doc_id)?
        .ok_or_else(|| anyhow!("Document not found after import"))?;
    updated_doc.character_count = total_chars;
    updated_doc.block_count = total_blocks as i64;
    uow.update_document(&updated_doc)?;

    Ok(total_blocks as i64)
}

